const item = $input.first().json;
const script = item.script || '';
const wordCount = script.trim().split(/\s+/).filter(Boolean).length;

if (wordCount < 1300) {
  throw new Error(`Script too short: ${wordCount} words (minimum 1300). Check Gemini response or prompt.`);
}
if (wordCount > 1650) {
  throw new Error(`Script too long: ${wordCount} words (maximum 1650). Check Gemini response or prompt.`);
}

// Check no markdown artifacts
if (/^#{1,6} /m.test(script)) {
  throw new Error('Script contains markdown headers. Gemini did not follow formatting rules.');
}
if (/\*\*.*\*\*/s.test(script)) {
  throw new Error('Script contains markdown bold. Gemini did not follow formatting rules.');
}

return [{ json: { ...item, wordCount } }];

const MAX_CHARS = 2500;
const item = $('Validate Script Length').first().json;
const script = item.script;

const paragraphs = script.split(/\n\s*\n/).map(p => p.trim()).filter(Boolean);

const chunks = [];
let current = '';

for (const para of paragraphs) {
  if (current && (current.length + para.length + 2) > MAX_CHARS) {
    chunks.push(current.trim());
    current = '';
  }
  if (para.length > MAX_CHARS) {
    const sentences = para.match(/[^.!?]+[.!?]+/g) || [para];
    for (const sent of sentences) {
      if (current && (current.length + sent.length + 1) > MAX_CHARS) {
        chunks.push(current.trim());
        current = '';
      }
      current += (current ? ' ' : '') + sent.trim();
    }
  } else {
    current += (current ? '\n\n' : '') + para;
  }
}
if (current.trim()) chunks.push(current.trim());

$workflow.staticData.chunkCount = chunks.length;
$workflow.staticData.episodeDate = item.episodeDate;
$workflow.staticData.fileId = item.fileId;
$workflow.staticData.wordCount = item.wordCount;
$workflow.staticData.modelUsed = item.modelUsed;
$workflow.staticData.script = item.script;

return chunks.map((text, i) => ({ json: { chunkIndex: i, text, totalChunks: chunks.length, episodeDate: item.episodeDate, script: item.script } }));

const items = $input.all();
const errors = [];

for (const item of items) {
  const { chunkIndex, text } = item.json;
  if (text.length > 4500) {
    errors.push(`Chunk ${chunkIndex} is ${text.length} chars (max 4500).`);
  }
  if (!/[.?!]$/.test(text.trim())) {
    errors.push(`Chunk ${chunkIndex} does not end with terminal punctuation: ..."${text.slice(-30)}"`);
  }
}

if (errors.length > 0) {
  throw new Error('Chunk validation failed:\n' + errors.join('\n'));
}

return items;

const fs = require('fs');
const item = $input.first();
const chunkIndex = item.json.chunkIndex !== undefined ? item.json.chunkIndex : ($workflow.staticData.savedChunks || 0);

// Extract request-id from response headers
const headers = item.json.headers || {};
const requestId = headers['request-id'] || headers['x-request-id'] || '';

// Update rolling previousRequestIds (last 3)
if (!$workflow.staticData.previousRequestIds) $workflow.staticData.previousRequestIds = [];
if (requestId) {
  $workflow.staticData.previousRequestIds.push(requestId);
  if ($workflow.staticData.previousRequestIds.length > 3) {
    $workflow.staticData.previousRequestIds.shift();
  }
}

// Track total chars processed
const chunkText = item.json.text || '';
$workflow.staticData.totalElevenLabsChars = ($workflow.staticData.totalElevenLabsChars || 0) + chunkText.length;

// Save binary to /tmp
const binaryData = item.binary && item.binary.data ? item.binary.data.data : null;
if (!binaryData) throw new Error(`No binary audio data for chunk ${chunkIndex}`);

const audioBuffer = Buffer.from(binaryData, 'base64');
const chunkPath = `/tmp/chunk_${chunkIndex}.mp3`;
fs.writeFileSync(chunkPath, audioBuffer);

$workflow.staticData.savedChunks = ($workflow.staticData.savedChunks || 0) + 1;

return [{ json: { chunkIndex, requestId, savedPath: chunkPath, chunkTextLength: chunkText.length } }];

const chunkCount = $workflow.staticData.chunkCount || 0;
const introPath = $env.INTRO_AUDIO_PATH || '/assets/intro.mp3';
const outroPath = $env.OUTRO_AUDIO_PATH || '/assets/outro.mp3';

const lines = [
  `file '${introPath}'`,
  ...Array.from({ length: chunkCount }, (_, i) => `file '/tmp/chunk_${i}.mp3'`),
  `file '${outroPath}'`,
];

const concatList = lines.join('\n');

return [{ json: { concatList, chunkCount } }];

const folderId = $input.first().json.id;
$workflow.staticData.driveFolderId = folderId;
return [{ json: { driveFolderId: folderId } }];

const fs = require('fs');
const mp3Buffer = fs.readFileSync('/tmp/episode.mp3');
const { execSync } = require('child_process');

// Get duration in seconds via ffprobe
let durationSeconds = 0;
try {
  const durStr = execSync(`ffprobe -v error -show_entries format=duration -of default=noprint_wrappers=1:nokey=1 /tmp/episode.mp3 2>/dev/null`).toString().trim();
  durationSeconds = parseFloat(durStr) || 0;
} catch(e) { /* ffprobe optional */ }

$workflow.staticData.durationSeconds = durationSeconds;

return [{
  json: { durationSeconds },
  binary: {
    episode: {
      data: mp3Buffer.toString('base64'),
      mimeType: 'audio/mpeg',
      fileName: 'episode.mp3'
    }
  }
}];

const script = $workflow.staticData.script || '';
const chunkCount = $workflow.staticData.chunkCount || 0;
const driveFolderId = $workflow.staticData.driveFolderId;

// Build script_chunks.json content
const chunks = Array.from({ length: chunkCount }, (_, i) => ({ chunkIndex: i, requestId: '' }));
const chunksJson = JSON.stringify(chunks, null, 2);

// Build metadata.json content
const now = new Date().toISOString();
const durationSeconds = $workflow.staticData.durationSeconds || 0;
const durationMin = Math.floor(durationSeconds / 60);
const durationSec = Math.round(durationSeconds % 60);

// ElevenLabs cost estimate: ~$0.0002 AUD per char on Pro tier
const totalChars = $workflow.staticData.totalElevenLabsChars || 0;
const elevenLabsCostAud = (totalChars * 0.0002).toFixed(2);
const geminiCostAud = '0.01';
const totalCostAud = (parseFloat(elevenLabsCostAud) + parseFloat(geminiCostAud)).toFixed(2);

const metadata = {
  timestamp: now,
  episodeDate: $workflow.staticData.episodeDate,
  sourcePdfFileId: $workflow.staticData.fileId,
  scriptWordCount: $workflow.staticData.wordCount,
  chunkCount,
  totalElevenLabsChars: totalChars,
  voiceId: $env.ELEVENLABS_VOICE_ID,
  modelId: 'eleven_turbo_v2_5',
  scriptModel: $workflow.staticData.modelUsed,
  durationSeconds: Math.round(durationSeconds),
  durationFormatted: `${durationMin}m ${durationSec}s`,
  estimatedCostAud: parseFloat(totalCostAud),
  geminiCostAud: parseFloat(geminiCostAud),
  elevenLabsCostAud: parseFloat(elevenLabsCostAud)
};

const metadataJson = JSON.stringify(metadata, null, 2);

return [{
  json: { driveFolderId },
  binary: {
    scriptMd: {
      data: Buffer.from(script).toString('base64'),
      mimeType: 'text/markdown',
      fileName: 'script.md'
    },
    chunksJson: {
      data: Buffer.from(chunksJson).toString('base64'),
      mimeType: 'application/json',
      fileName: 'script_chunks.json'
    },
    metadataJson: {
      data: Buffer.from(metadataJson).toString('base64'),
      mimeType: 'application/json',
      fileName: 'metadata.json'
    }
  }
}];
